use abi_resolver::decode::decode_with_function;
use abi_resolver::openchain::OpenchainIndex;
use abi_resolver::resolver::{ResolveOutcome, Resolver};
use abi_resolver::sourcify::SourcifyIndex;
use alloy_primitives::Address;
use std::str::FromStr;

fn main() {
    let bundle = include_bytes!("../data/sourcify.json");
    let index = SourcifyIndex::load_bundle(bundle).expect("bundle parses");
    println!("total functions indexed: {}", index.function_count());

    let addr = Address::from_str("0x66a9893cc07d91d95644aedd05d03f95e1dba8af").unwrap();
    let calldata_hex = "";
    let calldata = hex::decode(calldata_hex).unwrap();

    let selector = [calldata[0], calldata[1], calldata[2], calldata[3]];
    if let Some(info) = index.lookup(1, &addr, selector) {
        println!("LOOKUP HIT: {}", info.signature);
        match decode_with_function(&info.function, &calldata) {
            Ok(d) => println!("DECODE OK: signature={} args={}", d.signature, d.args.len()),
            Err(e) => println!("DECODE FAIL: {:?}", e),
        }
    }

    let resolver = Resolver::new(index, OpenchainIndex::empty());
    match resolver.resolve(1, &addr, &calldata) {
        ResolveOutcome::Resolved(r) => {
            println!(
                "RESOLVED: source={:?} signature={}",
                r.source, r.decoded.signature
            );
        }
        ResolveOutcome::NotFound => println!("NOT FOUND via resolver"),
    }
}
